import React from "react";
import AnimatedSection from "./AnimatedSection";

const MisionSection = () => (
  <AnimatedSection style={{ display: "flex", alignItems: "center", gap: "2rem", flexWrap: "wrap" }}>
    <div style={{ flex: 1, minWidth: "320px" }}>
      <h2 style={{ fontWeight: "900", fontSize: "2.5rem", marginBottom: "1rem", color: "#000000" }}>
        Nuestra Misión
      </h2>
      <p style={{ fontSize: "1.2rem", lineHeight: "1.6", color: "#000000" }}>
        Promover la conservación, investigación y difusión de las historias empresariales que han forjado Bolivia. Buscamos destacar los valores, logros y aprendizajes que han definido a cada organización en su camino hacia el bicentenario.
      </p>
    </div>
    <div style={{ flex: 1, minWidth: "320px" }}>
      <img
        src={require("../../assets/quien-contra-nosotros.jpg")}
        alt="Founders"
        style={{ width: "100%", borderRadius: "1rem", boxShadow: "0 0 15px rgba(0,0,0,0.15)" }}
      />
    </div>
  </AnimatedSection>
);

export default MisionSection;
